class Solution {
public:
    vector<int> separateDigits(vector<int>& nums) {
        vector<int> answer;
        for (int num : nums) {
            string str = to_string(num);
            for (char c : str) {
                answer.push_back(c - '0');
            }
        }
        return answer;
    }
};
